sql:
SELECT year, month, AVG(temp) AS average_temp
FROM climate_metrics
GROUP BY year, month;

SELECT AVG(mei) AS average_mei, AVG(co2) AS average_co2
FROM climate_metrics
WHERE year = 2020;

SELECT AVG(temp) AS average_temperature
FROM climate_metrics
WHERE year = 2023;

SELECT AVG(temp) AS average_temperature
FROM climate_metrics
WHERE year = 2022 AND month = 12;

external_knowledge:
- 'lighthouses' metaphorically refers to the locations mentioned in the data;
- 'beams of heat' is a metaphor for the temperature anomalies;
- 'warmest waters' refers to locations with the highest average temperature anomalies;
- 'shine their light from the hottest to the coolest' means ordering by average temperature in descending order.

sql:
SELECT temp
FROM climate_metrics
WHERE year = 2023 AND month = 10;

SELECT cm.year, l.location_name
FROM climate_metrics cm
INNER JOIN locations l ON cm.location_id = l.location_id;

SELECT AVG(co2) AS avg_co2, MIN(temp) AS min_temp, MAX(mei) AS max_mei
FROM climate_metrics
WHERE year > 2000;

SELECT AVG(temp) AS average_temperature
FROM climate_metrics
WHERE year = 1983 AND month = 1;

SELECT temp
FROM climate_metrics
WHERE year = 2020 AND month = 5 AND location_id = 1;
